  ('c1000000-0000-0000-0000-000000000280', '{"he":"מורה לחינוך מוזיקלי לגיל הרך עם ניסיון של כ-30 שנה. משלבת כלים מעולם המיינדפולנס (SEL) בלמידה.","en":"Teacher of early childhood music education with approximately 30 years of experience. Integrates tools from the world of mindfulness (SEL) in learning.","ar":"معلمة تعليم موسيقي في الطفولة المبكرة بخبرة حوالي 30 سنة. تدمج أدوات من عالم اليقظة الذهنية (SEL) في التعلم.","ru":"Преподаватель музыкального образования в раннем возрасте с опытом около 30 лет. Интегрирует инструменты из мира осознанности (SEL) в обучение."}'::jsonb, ARRAY["טרום כלי"]::TEXT[], ARRAY[]::TEXT[], NULL, TRUE, ARRAY[30,45,60]),
  ('c1000000-0000-0000-0000-000000000281', '{"he":"מנחה קבוצות מוזיקליות לגיל הרך בשיטת גורדון, תרפיסטית במוזיקה ופסיכותרפיסטית.","en":"Conductor of musical groups for early childhood using the Gordon method, music therapist and psychotherapist.","ar":"موصلة مجموعات موسيقية للطفولة المبكرة باستخدام طريقة غوردون، معالجة موسيقية وطبيبة نفسية.","ru":"Дирижер музыкальных групп для раннего детства с использованием метода Гордона, музыкальный терапевт и психотерапевт."}'::jsonb, ARRAY["מוסיקה לקטנטנים","פיתוח קול"]::TEXT[], ARRAY[]::TEXT[], NULL, TRUE, ARRAY[30,45,60])
