VALUES
  ('c1000000-0000-0000-0000-000000000282', '{"he":"מורה לפסנתר וליווי פסנתר.","en":"Teacher of piano and piano accompaniment.","ar":"معلمة البيانو والمرافقة الموسيقية على البيانو.","ru":"Преподаватель фортепиано и аккомпанемента на фортепиано."}'::jsonb, ARRAY["פסנתר","ליווי פסנתר"]::TEXT[], ARRAY[]::TEXT[], NULL, TRUE, ARRAY[30,45,60]),
  ('c1000000-0000-0000-0000-000000000283', '{"he":"ריכוז פדגוגי, מורה לתיאוריה, פסנתר, טרום כלי וארקנה.","en":"Pedagogical coordinator, teacher of music theory, piano, pre-instrumental music and Arcana.","ar":"منسقة تربوية، معلمة نظرية الموسيقى والبيانو وموسيقى ما قبل الآلات والأركانا.","ru":"Педагогический координатор, преподаватель теории музыки, фортепиано, доинструментальной музыки и Аркана."}'::jsonb, ARRAY["תיאוריה","פסנתר","טרום כלי"]::TEXT[], ARRAY[]::TEXT[], NULL, TRUE, ARRAY[30,45,60]),
  ('c1000000-0000-0000-0000-000000000284', '{"he":"מורה לעוד, תיפוף וגיטרה. מוביל חוג תיפוף בהוסטל.","en":"Teacher of oud, percussion and guitar. Leads a percussion ensemble at the hostel.","ar":"معلم العود والإيقاع والجيتار. يقود فريق الإيقاع في النزل.","ru":"Преподаватель уда, перкуссии и гитары. Руководит группой перкуссии в общежитии."}'::jsonb, ARRAY["עוד","תופים","גיטרה"]::TEXT[], ARRAY[]::TEXT[], NULL, TRUE, ARRAY[30,45,60]),
  ('c1000000-0000-0000-0000-000000000285', '{"he":"מורה לתיאוריה, פסנתר ולימודי ארקנה.","en":"Teacher of music theory, piano and Arcana studies.","ar":"معلمة نظرية الموسيقى والبيانو ودراسات الأركانا.","ru":"Преподаватель теории музыки, фортепиано и изучения Аркана."}'::jsonb, ARRAY["תיאוריה","פסנתר","ארקנה"]::TEXT[], ARRAY[]::TEXT[], NULL, TRUE, ARRAY[30,45,60]),
  ('c1000000-0000-0000-0000-000000000286', '{"he":"מורה לכינור בקונסרבטוריון.","en":"Teacher of violin at the conservatory.","ar":"معلمة الكمان في الكونسرفتوار.","ru":"Преподаватель скрипки в консерватории."}'::jsonb, ARRAY["כינור"]::TEXT[], ARRAY[]::TEXT[], NULL, TRUE, ARRAY[30,45,60]),
